	@Test
	void workerConfinedCloseOnceFilterClosesDelegateOnceEvenWhenCloseFails() throws Exception {
		Class<?> ownerType = Class
				.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.CloseOnceNativeBooleanFilter");
		Constructor<?> constructor = ownerType.getDeclaredConstructor(NativeBooleanFilter.class);
		constructor.setAccessible(true);
		IllegalStateException closeFailure = new IllegalStateException("synthetic worker-filter close failure");
		CloseTrackingFilter delegate = new CloseTrackingFilter(true, null, closeFailure);
		NativeBooleanFilter owner = (NativeBooleanFilter) constructor.newInstance(delegate);

		assertThatThrownBy(owner::close).isSameAs(closeFailure);
		assertThat(catchThrowable(owner::close)).isNull();
		assertThat(delegate.closeCalls).isOne();
	}

