	@Test
	void cancelledParallelSelectWorkerDoesNotPublishAttemptMetrics() throws Exception {
		CountDownLatch workerProbeEntered = new CountDownLatch(1);
		CountDownLatch releaseWorkerProbe = new CountDownLatch(1);
		ParallelPipelineSource worker = new ParallelPipelineSource(new long[] { 1L, 9L, 10L, 0L }, null, null,
				workerProbeEntered, releaseWorkerProbe, null);
		ParallelPipelineSource producer = new ParallelPipelineSource(new long[] { 1L, 7L, 8L, 0L }, null, null,
				null, null, null);
		ParallelSelectAttemptCounters before = ParallelSelectAttemptCounters.snapshot();
		long cancellationsBefore = LmdbNativeParallelPipelines.CANCELLED_RUNS.get();
		LmdbNativeParallelPipelines.ParallelRowCursor cursor = parallelTwoPatternRowCursor(worker, producer);
		CompletableFuture<Void> closing = null;

		try {
			await(workerProbeEntered);
			closing = CompletableFuture.runAsync(cursor::close);
			awaitCancellation(cursor);
			releaseWorkerProbe.countDown();
			closing.get(10L, TimeUnit.SECONDS);
		} finally {
			releaseWorkerProbe.countDown();
			if (closing != null && !closing.isDone()) {
				closing.get(10L, TimeUnit.SECONDS);
			}
			cursor.close();
		}

		assertThat(worker.closeCalls).isOne();
		assertThat(producer.closeCalls).isOne();
		assertThat(LmdbNativeParallelPipelines.CANCELLED_RUNS.get()).isEqualTo(cancellationsBefore + 1L);
		assertThat(ParallelSelectAttemptCounters.snapshot())
				.as("a cancelled parallel SELECT worker must discard its chunk, hash, memo, and SIP observations")
				.isEqualTo(before);
	}

	@Test
	void tryOpenClosesEachSourceOnceWhenWorkerSubmissionIsRejected() throws Exception {
		CountDownLatch running = new CountDownLatch(LmdbNativeParallelPipelines.MAX_POOL_TASKS);
		CountDownLatch release = new CountDownLatch(1);
		List<Future<?>> blockers = new ArrayList<>(LmdbNativeParallelPipelines.MAX_POOL_TASKS * 2);
		String previousThreads = System.getProperty("rdf4j.lmdb.parallel.threads");
		String previousMaxTasks = System.getProperty("rdf4j.lmdb.parallel.maxTasks");
		String previousThreshold = System.getProperty("rdf4j.lmdb.parallel.minRootEstimate");
		EveryCloseCountingSource[] siblings = { new EveryCloseCountingSource(), new EveryCloseCountingSource(),
				new EveryCloseCountingSource() };
		try {
			for (int i = 0; i < LmdbNativeParallelPipelines.MAX_POOL_TASKS; i++) {
				blockers.add(LmdbNativeParallelPipelines.pool().submit(() -> {
					running.countDown();
					await(release);
				}));
			}
			await(running);
			for (int i = 0; i < LmdbNativeParallelPipelines.MAX_POOL_TASKS; i++) {
				blockers.add(LmdbNativeParallelPipelines.pool().submit(() -> await(release)));
			}

			System.setProperty("rdf4j.lmdb.parallel.threads", "2");
			System.setProperty("rdf4j.lmdb.parallel.maxTasks", "3");
			System.setProperty("rdf4j.lmdb.parallel.minRootEstimate", "0");
			ParallelSourceOwner owner = new ParallelSourceOwner(siblings);
			NativeRowsStep step = twoPatternStep(owner);
			RowState row = new RowState(owner, step.layout, EmptyBindingSet.getInstance());
			Arrays.fill(row.slots, NativeLmdbQuerySource.UNKNOWN_ID);

			assertThatThrownBy(() -> LmdbNativeParallelPipelines.tryOpen(step, row))
					.isInstanceOf(RejectedExecutionException.class);
			assertThat(siblings).allSatisfy(source -> assertThat(source.closeCalls).isOne());
		} finally {
			release.countDown();
			for (Future<?> blocker : blockers) {
				blocker.get(10L, TimeUnit.SECONDS);
			}
			restoreProperty("rdf4j.lmdb.parallel.threads", previousThreads);
			restoreProperty("rdf4j.lmdb.parallel.maxTasks", previousMaxTasks);
			restoreProperty("rdf4j.lmdb.parallel.minRootEstimate", previousThreshold);
		}
	}

