	@Test
	void workerSetupFailureClosesPlanFilterBeforeSourceAndRetainsFailureOrder() {
		IllegalStateException setupFailure = new IllegalStateException("synthetic worker seeding failure");
		IllegalArgumentException filterCloseFailure = new IllegalArgumentException(
				"synthetic worker-filter cleanup failure");
		AssertionError sourceCloseFailure = new AssertionError("synthetic worker-source cleanup failure");
		SetupParallelSource worker = new SetupParallelSource(setupFailure, sourceCloseFailure);
		SetupParallelSource producer = new SetupParallelSource(null, null);
		NativeRowsStep step = twoPatternStep(worker);
		MultiJoinPlan original = (MultiJoinPlan) step.arg;
		RecordingFilterFixture filter = new RecordingFilterFixture(true, null, filterCloseFailure);
		MultiJoinPlan workerPlan = new MultiJoinPlan(original.children,
				new MaskedFilter[] { new MaskedFilter(filter.recording, 0L) });
		QueryBindingSet base = new QueryBindingSet();
		base.addBinding("subject", SimpleValueFactory.getInstance().createIRI("urn:bound-subject"));
		RowState consumerRow = new RowState(worker, step.layout, base);
		LmdbNativeParallelPipelines.ParallelRowCursor cursor = new LmdbNativeParallelPipelines.ParallelRowCursor(step,
				consumerRow, (PatternPlan) original.children[0], new MultiJoinPlan[] { workerPlan },
				new NativeLmdbQuerySource.ParallelSource[] { worker, producer },
				new LmdbNativeParallelPipelines.TaskReservation(0), false);

		Throwable problem;
		cursor.start();
		try {
			problem = catchThrowable(cursor::next);
		} finally {
			cursor.close();
		}

		assertThat(problem).isSameAs(setupFailure);
		assertThat(problem.getSuppressed()).containsExactly(filterCloseFailure, sourceCloseFailure);
		assertThat(filter.delegate.closeCalls).isOne();
		assertThat(((CloseTrackingSource) worker).closeCalls).isOne();
		assertThat(((CloseTrackingSource) producer).closeCalls).isOne();
	}

