	void factorizedTailCloseReleasesGroupedMemoReservationsExactlyOnce() {
		FactorizedTail.MemoBudget budget = new FactorizedTail.MemoBudget(FactorizedTail.MEMO_BYPASSES);
		assertThat(budget.tryReserve(FactorizedTail.MEMO_MAX_ENTRIES - 1,
				FactorizedTail.MEMO_MAX_STORED_VALUES - 2)).isTrue();
		FactorizedTail tail = new FactorizedTail(new Branch[0], budget, new AggregateSpec[0], new int[0],
				new int[0], -1, false, new NativeBooleanFilter[0]);
		tail.groupedMemo = new HashMap<>();
		assertThat(budget.tryReserve(1, 2)).isTrue();
		tail.groupedMemo.put(new GroupKey(new long[0]), new long[2]);

		tail.close();
		assertThat(tail.groupedMemo).isNullOrEmpty();
		assertThat(budget.tryReserve(1, 2))
				.as("closing the grouped memo must return its entry and physical pair-array capacity")
				.isTrue();
		tail.close();
		assertThat(budget.tryReserve(1, 2))
				.as("a repeated close must not release the grouped reservation twice")
				.isFalse();
	}

