	@Test
	void chunkFilterStageRetainsBothCloseFailuresAndClosesEachOwnerOnce() {
		IllegalStateException upstreamFailure = new IllegalStateException("synthetic chunk upstream close failure");
		IllegalArgumentException filterFailure = new IllegalArgumentException("synthetic chunk filter close failure");
		OneRowBatchStage upstream = new OneRowBatchStage(new long[] { 21L }, upstreamFailure);
		RecordingFilterFixture filter = new RecordingFilterFixture(true, null, filterFailure);
		RowState row = rowState(new CloseTrackingSource(null));
		LmdbNativeChunkPipeline.ChunkPrefixRowCursor cursor = new LmdbNativeChunkPipeline.ChunkPrefixRowCursor(
				new LmdbNativeChunkPipeline.FilterStage(upstream, filter.recording, row), row);

		Throwable problem = catchThrowable(cursor::close);
		assertThat(problem).isIn(upstreamFailure, filterFailure);
		Throwable secondary = problem == upstreamFailure ? filterFailure : upstreamFailure;
		assertThat(problem.getSuppressed()).containsExactly(secondary);
		assertThat(upstream.closeCalls).isOne();
		assertThat(filter.delegate.closeCalls).isOne();
		cursor.close();
		assertThat(upstream.closeCalls).isOne();
		assertThat(filter.delegate.closeCalls).isOne();
	}

