	@Test
	void speculativeFilterLeaseDiscardsAttemptFeedbackWithoutClosingReusableDelegate() throws Exception {
		Class<?> leaseType = Class.forName("org.eclipse.rdf4j.sail.lmdb.evaluation.NativeFilterLease");
		Constructor<?> constructor = leaseType.getDeclaredConstructor();
		constructor.setAccessible(true);
		Object lease = constructor.newInstance();
		Method borrow = leaseType.getDeclaredMethod("borrow", NativeBooleanFilter.class);
		Method discard = leaseType.getDeclaredMethod("discard");
		borrow.setAccessible(true);
		discard.setAccessible(true);

		RecordingFilterFixture fixture = new RecordingFilterFixture(true, null, null);
		NativeBooleanFilter borrowed = (NativeBooleanFilter) borrow.invoke(lease, fixture.recording);
		assertThat(borrow.invoke(lease, fixture.recording))
				.as("one attempt must use one identity-stable borrowed facade per compiled filter")
				.isSameAs(borrowed);
		assertThat(borrowed.accept(rowState(new CloseTrackingSource(null)))).isTrue();
		borrowed.close();
		discard.invoke(lease);

		assertThat(fixture.recording.passed).hasValue(0L);
		assertThat(fixture.recording.filtered).hasValue(0L);
		assertThat(fixture.delegate.closeCalls)
				.as("discarded speculative feedback must leave the original delegate open for fallback")
				.isZero();
		assertThat(fixture.recording.accept(rowState(new CloseTrackingSource(null)))).isTrue();
		fixture.recording.close();
		assertThat(fixture.delegate.closeCalls).isOne();
	}

	@Test
	void parallelAggregationKeepsWorkerFailurePrimaryWhenFactorizedTailCloseAlsoFails() {
		IllegalArgumentException workerFailure = new IllegalArgumentException(
				"synthetic factorized worker scan failure");
		IllegalStateException closeFailure = new IllegalStateException("synthetic factorized tail close failure");
		WorkerFailureSource source = new WorkerFailureSource(workerFailure, closeFailure);
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("subject", 0, "value", 1), null);
		layout.freeze(List.of("subject", "value"));
		PatternPlan root = new PatternPlan(Term.slot(0), Term.constant(7), Term.constant(8), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 1D);
		PatternPlan branch = new PatternPlan(Term.slot(0), Term.constant(9), Term.slot(1), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 10D);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { root, branch }, new MaskedFilter[0]);
		MultiJoinPlan.OrderedPlan derived = plan.derivedFactorizedPlan(rowState(source, layout));
		assertThat(derived.order[0]).isSameAs(root);
		AggregateSpec[] aggregates = { AggregateSpec.slot("sum", 1, false, AggKind.SUM) };
		NativeGroupIteration iteration = new NativeGroupIteration(source, plan, layout, new int[0], aggregates, false,
				EmptyBindingSet.getInstance(), null, null, false, null);
		ArrayBlockingQueue<LmdbNativeExchange.Morsel> queue = new ArrayBlockingQueue<>(2);
		queue.add(new LmdbNativeExchange.Morsel(new long[] { 1L, 7L, 8L, 0L }, 1));
		queue.add(LmdbNativeExchange.Morsel.POISON);

		assertThatThrownBy(() -> LmdbNativeParallelAggregation.runWorker(iteration, plan, derived, root, source,
				queue, new AtomicReference<>(), LmdbNativeAttemptMetrics.direct()))
						.isSameAs(workerFailure)
						.satisfies(problem -> assertThat(problem.getSuppressed()).containsExactly(closeFailure));
		assertThat(source.probeCloseCalls).isOne();
	}

	private static Branch branch(FactorizedTail.MemoBudget budget, CloseTrackingProbe probe) {
		Branch branch = new Branch(pattern(), new int[0], new int[0], false, false, -1, -1, budget,
				new NativeBooleanFilter[0], new int[0], new int[0]);
		branch.probe = probe;
		return branch;
	}

	private static PatternPlan pattern() {
		return new PatternPlan(Term.unbound(), Term.constant(7), Term.unbound(), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 1D);
	}

	private static RowState rowState(NativeLmdbQuerySource source) {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("value", 0), null);
		layout.freeze(List.of("value"));
		return rowState(source, layout);
	}

	private static RowState rowState(NativeLmdbQuerySource source, NativeSlotLayout layout) {
		RowState row = new RowState(source, layout, EmptyBindingSet.getInstance());
		Arrays.fill(row.slots, NativeLmdbQuerySource.UNKNOWN_ID);
		row.recomputeBoundMask();
		return row;
	}

	private static LmdbNativeParallelPipelines.ParallelRowCursor parallelRowCursor(
			ParallelPipelineSource worker, ParallelPipelineSource producer) {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("subject", 0), null);
		layout.freeze(List.of("subject"));
		PatternPlan root = new PatternPlan(Term.slot(0), Term.constant(7), Term.constant(8), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 1D);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { root }, new MaskedFilter[0]);
		NativeRowsStep step = new NativeRowsStep(worker, plan, layout, new int[] { 0 }, new String[] { "subject" },
				false, new int[0], new boolean[0], 0L, -1L, false, null, null, null, Set.of(), null, null);
		RowState consumerRow = new RowState(worker, layout, EmptyBindingSet.getInstance());
		return new LmdbNativeParallelPipelines.ParallelRowCursor(step, consumerRow, root,
				new MultiJoinPlan[] { plan },
				new NativeLmdbQuerySource.ParallelSource[] { worker, producer },
				new LmdbNativeParallelPipelines.TaskReservation(0));
	}

	private static LmdbNativeParallelPipelines.ParallelRowCursor parallelTwoPatternRowCursor(
			ParallelPipelineSource worker, ParallelPipelineSource producer) {
		NativeRowsStep step = twoPatternStep(worker);
		MultiJoinPlan plan = (MultiJoinPlan) step.arg;
		PatternPlan root = (PatternPlan) plan.children[0];
		RowState consumerRow = new RowState(worker, step.layout, EmptyBindingSet.getInstance());
		return new LmdbNativeParallelPipelines.ParallelRowCursor(step, consumerRow, root,
				new MultiJoinPlan[] { plan },
				new NativeLmdbQuerySource.ParallelSource[] { worker, producer },
				new LmdbNativeParallelPipelines.TaskReservation(0));
	}

	private static NativeRowsStep twoPatternStep(NativeLmdbQuerySource source) {
		NativeSlotLayout layout = new NativeSlotLayout(Map.of("subject", 0, "object", 1), null);
		layout.freeze(List.of("subject", "object"));
		PatternPlan root = new PatternPlan(Term.slot(0), Term.constant(7), Term.constant(8), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 1D);
		PatternPlan tail = new PatternPlan(Term.slot(0), Term.constant(9), Term.slot(1), Term.unbound(),
				ContextConstraint.UNRESTRICTED, false, 2D);
		MultiJoinPlan plan = new MultiJoinPlan(new SlotPlan[] { root, tail }, new MaskedFilter[0]);
		return new NativeRowsStep(source, plan, layout, new int[] { 0, 1 }, new String[] { "subject", "object" },
				false, new int[0], new boolean[0], 0L, -1L, false, null, null, null, Set.of(), null, null);
	}

	private static void awaitTaskCount(LmdbNativeParallelPipelines.ParallelRowCursor cursor, long expected) {
		long deadline = System.nanoTime() + TimeUnit.SECONDS.toNanos(10L);
		while (cursor.tasks.getCount() != expected && System.nanoTime() < deadline) {
			Thread.yield();
		}
		assertThat(cursor.tasks.getCount()).isEqualTo(expected);
	}

	private static void awaitCancellation(LmdbNativeParallelPipelines.ParallelRowCursor cursor) {
		long deadline = System.nanoTime() + TimeUnit.SECONDS.toNanos(10L);
		while (!cursor.cancelled.get() && System.nanoTime() < deadline) {
			Thread.yield();
		}
		assertThat(cursor.cancelled.get()).isTrue();
	}

	private static void await(CountDownLatch latch) {
		ParallelPipelineSource.await(latch);
	}

	private static void restoreProperty(String property, String value) {
		if (value == null) {
			System.clearProperty(property);
		} else {
			System.setProperty(property, value);
		}
	}

	private static Throwable fallbackWithCloseFailure(RuntimeException closeFailure) {
		try (AutoCloseable ignored = () -> {
			throw closeFailure;
		}) {
			throw EncounterOrderFallback.floatingSumOrAvg();
		} catch (Throwable problem) {
			return problem;
		}
	}

