	private static final class FallbackThenCloseFailurePlan implements SlotPlan {
		private final RuntimeException closeFailure;

		private FallbackThenCloseFailurePlan(RuntimeException closeFailure) {
			this.closeFailure = closeFailure;
		}

		@Override
		public RowCursor open(RowState row) {
			return new RowCursor() {
				@Override
				public boolean next() {
					throw EncounterOrderFallback.floatingSumOrAvg();
				}

				@Override
				public void close() {
					throw closeFailure;
				}
			};
		}

		@Override
		public long producedMask() {
			return 0L;
		}
	}

	private static final class RecordingFilterFixture {
		private final CloseTrackingFilter delegate;
		private final RecordingNativeBooleanFilter recording;

		private RecordingFilterFixture(boolean accepted, RuntimeException acceptFailure,
				RuntimeException closeFailure) {
			delegate = new CloseTrackingFilter(accepted, acceptFailure, closeFailure);
			Filter model = new Filter(new SingletonSet(),
					new ValueConstant(SimpleValueFactory.getInstance().createLiteral(true)));
			recording = new RecordingNativeBooleanFilter(delegate, model, new EvaluationStatistics());
		}
	}

	private static final class CloseTrackingFilter implements NativeBooleanFilter {
		private final boolean accepted;
		private final RuntimeException acceptFailure;
		private final RuntimeException closeFailure;
		private int acceptCalls;
		private int closeCalls;

		private CloseTrackingFilter(boolean accepted, RuntimeException acceptFailure, RuntimeException closeFailure) {
			this.accepted = accepted;
			this.acceptFailure = acceptFailure;
			this.closeFailure = closeFailure;
		}

		@Override
		public boolean accept(RowState row) {
			acceptCalls++;
			if (acceptFailure != null) {
				throw acceptFailure;
			}
			return accepted;
		}

		@Override
		public void close() {
			closeCalls++;
			if (closeFailure != null) {
				throw closeFailure;
			}
		}
	}

	private static final class OneRowBatchStage implements LmdbNativeChunkPipeline.BatchStage {
		private final long[] row;
		private final RuntimeException closeFailure;
		private boolean emitted;
		private int closeCalls;

		private OneRowBatchStage(long[] row, RuntimeException closeFailure) {
			this.row = row;
			this.closeFailure = closeFailure;
		}

		@Override
		public int fill(NativeBatch out) {
			out.clear();
			if (emitted) {
				return 0;
			}
			emitted = true;
			out.copyFromRow(row, 0);
			out.finishRows(1);
			return 1;
		}

		@Override
		public void close() {
			closeCalls++;
			emitted = true;
			if (closeFailure != null) {
				throw closeFailure;
			}
		}
	}

	private static final class WorkerFailureSource extends CloseTrackingSource {
		private final RuntimeException workerFailure;
		private final RuntimeException probeCloseFailure;
		private int probeCloseCalls;

		private WorkerFailureSource(RuntimeException workerFailure, RuntimeException probeCloseFailure) {
			super(null);
			this.workerFailure = workerFailure;
			this.probeCloseFailure = probeCloseFailure;
		}

		@Override
		public Value lazyValue(long id) {
			return SimpleValueFactory.getInstance().createLiteral(id);
		}

		@Override
		public NativeProbe newProbe() {
			return new NativeProbe() {
				@Override
				public RecordIterator open(long subj, long pred, long obj, long context) {
					return new RecordIterator() {
						@Override
						public long[] next() {
							throw workerFailure;
						}

						@Override
						public void close() {
						}
					};
				}

				@Override
				public void close() {
					probeCloseCalls++;
					throw probeCloseFailure;
				}
			};
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return pred == 7L ? 1D : 10D;
		}
	}

	private static final class CloseTrackingProbe implements NativeLmdbQuerySource.NativeProbe {
		private final Throwable closeFailure;
		private int closeCalls;
		private boolean closed;

		private CloseTrackingProbe(Throwable closeFailure) {
			this.closeFailure = closeFailure;
		}

		@Override
		public RecordIterator open(long subj, long pred, long obj, long context) {
			throw new UnsupportedOperationException();
		}

		@Override
		public void close() {
			if (!closed) {
				closed = true;
				closeCalls++;
				if (closeFailure instanceof RuntimeException) {
					throw (RuntimeException) closeFailure;
				}
				if (closeFailure != null) {
					throw (Error) closeFailure;
				}
			}
		}
	}

	private static final class ParallelPipelineSource implements NativeLmdbQuerySource.ParallelSource {
		private static final RecordIterator EMPTY = new RecordIterator() {
			@Override
			public long[] next() {
				return null;
			}

			@Override
			public void close() {
			}
		};

		private final long[] row;
		private final IOException scanFailure;
		private final RuntimeException closeFailure;
		private final CountDownLatch statementsEntered;
		private final CountDownLatch releaseStatements;
		private final CountDownLatch closeBarrier;
		private int closeCalls;
		private boolean closed;

		private ParallelPipelineSource(IOException scanFailure, RuntimeException closeFailure) {
			this(null, scanFailure, closeFailure, null, null, null);
		}

		private ParallelPipelineSource(long[] row, IOException scanFailure, RuntimeException closeFailure,
				CountDownLatch statementsEntered, CountDownLatch releaseStatements, CountDownLatch closeBarrier) {
			this.row = row;
			this.scanFailure = scanFailure;
			this.closeFailure = closeFailure;
			this.statementsEntered = statementsEntered;
			this.releaseStatements = releaseStatements;
			this.closeBarrier = closeBarrier;
		}

		@Override
		public void close() {
			if (!closed) {
				await(closeBarrier);
				closed = true;
				closeCalls++;
				if (closeFailure != null) {
					throw closeFailure;
				}
			}
		}

		@Override
		public long idOf(Value value) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Value lazyValue(long id) {
			throw new UnsupportedOperationException();
		}

		@Override
		public Object idSpace() {
			return this;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) throws IOException {
			if (statementsEntered != null) {
				statementsEntered.countDown();
			}
			await(releaseStatements);
			if (scanFailure != null) {
				throw scanFailure;
			}
			if (row == null) {
				return EMPTY;
			}
			return new RecordIterator() {
				private boolean emitted;

				@Override
				public long[] next() {
					if (emitted) {
						return null;
					}
					emitted = true;
					return row;
				}

				@Override
				public void close() {
				}
			};
		}

		@Override
		public long count(long subj, long pred, long obj, long context) {
			return 0L;
		}

		@Override
		public boolean has(long subj, long pred, long obj, long context) {
			return false;
		}

		@Override
		public double estimate(long subj, long pred, long obj, long context) {
			return 0D;
		}

		@Override
		public boolean hasStatementsInSource() {
			return false;
		}

		private static void await(CountDownLatch latch) {
			if (latch == null) {
				return;
			}
			try {
				if (!latch.await(10L, TimeUnit.SECONDS)) {
					throw new AssertionError("timed out awaiting parallel pipeline test coordination");
				}
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				throw new AssertionError("interrupted awaiting parallel pipeline test coordination", e);
			}
		}
	}

