	private static final class ParallelSourceOwner extends CloseTrackingSource {
		private final Object idSpace;
		private final NativeLmdbQuerySource.ParallelSource[] siblings;
		private int openParallelSourcesCalls;
		private int statementsCalls;

		private ParallelSourceOwner(NativeLmdbQuerySource.ParallelSource[] siblings) {
			this(null, siblings);
		}

		private ParallelSourceOwner(Object idSpace, NativeLmdbQuerySource.ParallelSource[] siblings) {
			super(null);
			this.idSpace = idSpace;
			this.siblings = siblings;
		}

		@Override
		public Object idSpace() {
			return idSpace != null ? idSpace : this;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			statementsCalls++;
			throw new AssertionError("the original query source must not own the prepared root scan");
		}

		@Override
		public NativeLmdbQuerySource.ParallelSource[] openParallelSources(int count) {
			assertThat(count).isEqualTo(siblings.length);
			openParallelSourcesCalls++;
			return siblings;
		}
	}

	private static final class ExactSumParallelSource extends CloseTrackingSource {
		private final Object idSpace;
		private final int rootRows;
		private final boolean producer;
		private int statementsCalls;
		private int rowsRead;
		private int cursorCloseCalls;

		private ExactSumParallelSource(Object idSpace, int rootRows, boolean producer) {
			super(null);
			this.idSpace = idSpace;
			this.rootRows = rootRows;
			this.producer = producer;
		}

		static ExactSumParallelSource worker(Object idSpace) {
			return new ExactSumParallelSource(idSpace, 0, false);
		}

		static ExactSumParallelSource producer(Object idSpace, int rootRows) {
			return new ExactSumParallelSource(idSpace, rootRows, true);
		}

		@Override
		public Object idSpace() {
			return idSpace;
		}

		@Override
		public Value lazyValue(long id) {
			if (ValueIds.getIdType(id) != ValueIds.T_INTEGER) {
				throw new AssertionError("expected an inline integer id, got " + id);
			}
			return SimpleValueFactory.getInstance().createLiteral(ValueIds.getValue(id));
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			if (!producer) {
				throw new AssertionError("worker siblings must consume the external root morsels");
			}
			if (subj != 1L || pred != 7L || obj != NativeLmdbQuerySource.UNKNOWN_ID
					|| context != NativeLmdbQuerySource.UNKNOWN_ID) {
				throw new AssertionError("unexpected prepared-root scan");
			}
			statementsCalls++;
			if (statementsCalls != 1) {
				throw new AssertionError("prepared producer root was reopened");
			}
			return new RecordIterator() {
				private int nextValue = 1;
				private boolean closed;

				@Override
				public long[] next() {
					if (nextValue > rootRows) {
						return null;
					}
					long value = ValueIds.createId(ValueIds.T_INTEGER, nextValue++);
					rowsRead++;
					return new long[] { 1L, 7L, value, 0L };
				}

				@Override
				public void close() {
					if (!closed) {
						closed = true;
						cursorCloseCalls++;
					}
				}
			};
		}
	}

	private static final class SnapshotOpenCountingSource extends CloseTrackingSource {
		private int openParallelSourcesCalls;

		private SnapshotOpenCountingSource() {
			super(null);
		}

		@Override
		public NativeLmdbQuerySource.ParallelSource[] openParallelSources(int count) {
			openParallelSourcesCalls++;
			NativeLmdbQuerySource.ParallelSource[] sources = new NativeLmdbQuerySource.ParallelSource[count];
			for (int i = 0; i < count; i++) {
				sources[i] = new CloseTrackingSource(null);
			}
			return sources;
		}
	}

	private static final class FloatingRootSource extends CloseTrackingSource {
		// Any odd inline id carries the LMDB double tag; lazyValue supplies the representative test literal.
		private static final long FLOATING_VALUE_ID = 43L;
		private static final long EXACT_VALUE_ID = ValueIds.createId(ValueIds.T_DECIMAL, 1L);

		private final FloatingRootSource counters;
		private final boolean snapshotSibling;
		private final boolean producerSibling;
		private final long[] rootValues;
		private int openParallelSourcesCalls;
		private int originalRootOpenCalls;
		private int rootOpenCalls;
		private int rootCloseCalls;
		private int branchOpenCalls;
		private int branchCloseCalls;
		private int producerProbeCreations;
		private int producerProbeOpens;
		private int producerProbeCloses;

		private FloatingRootSource(long... rootValues) {
			super(null);
			this.counters = this;
			this.snapshotSibling = false;
			this.producerSibling = false;
			this.rootValues = rootValues.length == 0 ? new long[] { FLOATING_VALUE_ID } : rootValues;
		}

		private FloatingRootSource(FloatingRootSource counters, boolean producerSibling) {
			super(null);
			this.counters = counters;
			this.snapshotSibling = true;
			this.producerSibling = producerSibling;
			this.rootValues = counters.rootValues;
		}

		@Override
		public Value lazyValue(long id) {
			return id == FLOATING_VALUE_ID ? SimpleValueFactory.getInstance().createLiteral(0.1d)
					: SimpleValueFactory.getInstance().createLiteral(1);
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			if (!snapshotSibling) {
				originalRootOpenCalls++;
				throw new AssertionError("root preflight escaped the pinned producer snapshot");
			}
			if ((subj == 2L && pred == 8L) || (subj == 3L && pred == 9L)) {
				counters.branchOpenCalls++;
				return new RecordIterator() {
					private boolean closed;

					@Override
					public long[] next() {
						return null;
					}

					@Override
					public void close() {
						if (!closed) {
							closed = true;
							counters.branchCloseCalls++;
						}
					}
				};
			}
			assertThat(subj).isEqualTo(1L);
			assertThat(pred).isEqualTo(7L);
			counters.rootOpenCalls++;
			return new RecordIterator() {
				private int index;
				private boolean closed;

				@Override
				public long[] next() {
					if (index >= rootValues.length) {
						return null;
					}
					return new long[] { 1L, 7L, rootValues[index++], 0L };
				}

				@Override
				public void close() {
					if (!closed) {
						closed = true;
						counters.rootCloseCalls++;
					}
				}
			};
		}

		@Override
		public NativeProbe newProbe() {
			if (producerSibling) {
				counters.producerProbeCreations++;
			}
			return new NativeProbe() {
				private RecordIterator current;
				private boolean closed;

				@Override
				public RecordIterator open(long subj, long pred, long obj, long context) {
					if (current != null) {
						current.close();
					}
					if (producerSibling) {
						counters.producerProbeOpens++;
					}
					current = statements(subj, pred, obj, context);
					return current;
				}

				@Override
				public void close() {
					if (!closed) {
						closed = true;
						if (current != null) {
							current.close();
							current = null;
						}
						if (producerSibling) {
							counters.producerProbeCloses++;
						}
					}
				}
			};
		}

		@Override
		public NativeLmdbQuerySource.ParallelSource[] openParallelSources(int count) {
			assertThat(snapshotSibling).isFalse();
			openParallelSourcesCalls++;
			NativeLmdbQuerySource.ParallelSource[] sources = new NativeLmdbQuerySource.ParallelSource[count];
			for (int i = 0; i < count; i++) {
				sources[i] = new FloatingRootSource(this, i == count - 1);
			}
			return sources;
		}
	}

	private static final class ConstantSlotPreflightSource extends CloseTrackingSource {
		private static final long VALUE_A = 43L;
		private static final long VALUE_B = 45L;

		private final ConstantSlotPreflightSource counters;
		private final boolean snapshotSibling;
		private final boolean producerSibling;
		private final long[] rootValues;
		private int producerProbeOpens;
		private int workerProbeOpens;

		private ConstantSlotPreflightSource(long... rootValues) {
			super(null);
			this.counters = this;
			this.snapshotSibling = false;
			this.producerSibling = false;
			this.rootValues = rootValues;
		}

		private ConstantSlotPreflightSource(ConstantSlotPreflightSource counters, boolean producerSibling) {
			super(null);
			this.counters = counters;
			this.snapshotSibling = true;
			this.producerSibling = producerSibling;
			this.rootValues = counters.rootValues;
		}

		@Override
		public Value lazyValue(long id) {
			return SimpleValueFactory.getInstance().createLiteral(id == VALUE_A ? 0.1d : 0.2d);
		}

		@Override
		public Object idSpace() {
			return counters;
		}

		@Override
		public RecordIterator statements(long subj, long pred, long obj, long context) {
			assertThat(snapshotSibling).isTrue();
			if (subj == 1L && pred == 7L) {
				return iterator(new long[][] { { 1L, 7L, rootValues[0], 0L }, { 1L, 7L, rootValues[1], 0L } });
			}
			if (subj == 2L && pred == 8L && obj == VALUE_A) {
				return iterator(new long[][] { { 2L, 8L, VALUE_A, 0L } });
			}
			if (subj == VALUE_B && pred == 9L && obj == VALUE_B) {
				return iterator(new long[][] { { VALUE_B, 9L, VALUE_B, 0L } });
			}
			return iterator(new long[0][]);
		}

		@Override
		public NativeProbe newProbe() {
			return new NativeProbe() {
				private RecordIterator current;
				private boolean closed;

				@Override
				public RecordIterator open(long subj, long pred, long obj, long context) {
					if (current != null) {
						current.close();
					}
					if (producerSibling) {
						counters.producerProbeOpens++;
					} else {
						counters.workerProbeOpens++;
					}
					current = statements(subj, pred, obj, context);
					return current;
				}

				@Override
				public void close() {
					if (!closed) {
						closed = true;
						if (current != null) {
							current.close();
							current = null;
						}
					}
				}
			};
		}

		@Override
		public NativeLmdbQuerySource.ParallelSource[] openParallelSources(int count) {
			assertThat(snapshotSibling).isFalse();
			NativeLmdbQuerySource.ParallelSource[] sources = new NativeLmdbQuerySource.ParallelSource[count];
			for (int i = 0; i < count; i++) {
				sources[i] = new ConstantSlotPreflightSource(this, i == count - 1);
			}
			return sources;
		}

		private static RecordIterator iterator(long[][] rows) {
			return new RecordIterator() {
				private int index;

				@Override
				public long[] next() {
					return index < rows.length ? rows[index++] : null;
				}

				@Override
				public void close() {
				}
			};
		}
	}

